import React, { useMemo } from 'react';

export default function CoverPage({ book }) {
  const stars = useMemo(() =>
    Array.from({ length: 50 }, (_, i) => ({
      id: i,
      x: Math.random() * 100, y: Math.random() * 100,
      s: Math.random() * 3 + 1, delay: Math.random() * 5, dur: 2 + Math.random() * 3,
    })), []);

  return (
    <div className="cover" style={{ gridColumn: 'span 2' }}>
      <style>{`
        @keyframes cvtw { 0%,100%{opacity:.2;transform:scale(1)} 50%{opacity:.9;transform:scale(1.4)} }
        .cover {
          position:relative; overflow:hidden;
          background:linear-gradient(135deg,#0f0c29 0%,#302b63 50%,#24243e 100%);
          display:flex; align-items:center; justify-content:center;
        }
        .cover-star { position:absolute; border-radius:50%; background:#fff; animation:cvtw var(--d) ease-in-out infinite; }
        .cover-content { position:relative; z-index:2; text-align:center; padding:40px; }
        .cover-ornament {
          font-size:clamp(10px,1.5vw,16px); letter-spacing:1em;
          color:rgba(240,192,64,.45); margin-bottom:22px;
        }
        .cover-title {
          font-family:'Cinzel',serif;
          font-size:clamp(20px,4.5vw,54px);
          color:#f0c040; font-weight:700; line-height:1.1;
          text-shadow:0 0 40px rgba(240,192,64,.35);
          margin-bottom:18px; letter-spacing:.05em;
        }
        .cover-subtitle {
          font-family:'IM Fell English',serif; font-style:italic;
          font-size:clamp(9px,1.3vw,14px);
          color:rgba(240,220,160,.45); margin-bottom:16px;
          letter-spacing:.06em;
        }
        .cover-line { width:55px; height:1px; margin:0 auto 18px; background:linear-gradient(90deg,transparent,rgba(240,192,64,.55),transparent); }
        .cover-author {
          font-family:'Cormorant Garamond',serif;
          font-size:clamp(11px,1.6vw,18px); color:rgba(240,220,160,.55);
          letter-spacing:.1em; margin-bottom:28px;
        }
        .cover-emblem { font-size:clamp(18px,2.8vw,34px); color:rgba(240,192,64,.25); }
        .cover-open-hint {
          margin-top:22px; font-family:'Cinzel',serif; font-size:clamp(7px,1vw,9px);
          letter-spacing:.3em; color:rgba(240,192,64,.25); text-transform:uppercase;
          animation:pulse 2.5s ease-in-out infinite;
        }
        @keyframes pulse { 0%,100%{opacity:.25} 50%{opacity:.65} }
      `}</style>

      {stars.map(s => (
        <div key={s.id} className="cover-star" style={{
          left:`${s.x}%`, top:`${s.y}%`, width:s.s, height:s.s,
          '--d':`${s.dur}s`, animationDelay:`${s.delay}s`,
        }} />
      ))}

      <div className="cover-content">
        <div className="cover-ornament">✦ ✦ ✦</div>
        <h1 className="cover-title">{book.title}</h1>
        {book.subtitle && <p className="cover-subtitle">{book.subtitle}</p>}
        <div className="cover-line" />
        <p className="cover-author">by {book.author}</p>
        <div className="cover-emblem">⭑</div>
        <p className="cover-open-hint">Click → to open</p>
      </div>
    </div>
  );
}
